import type { ProduceItem, Category } from './types'

// Bulk dataset expansion. Entries are authored in a compact tuple form and
// expanded into full ProduceItem objects by `toItem` below. Each row is:
//
//   [id, name, category, lat, lng, region, story,
//    calories, carbs, fiber, protein, highlights, tasteAtlasSlug, commonsFile]
//
// Nutrition is per 100 g of the raw edible portion (approximate, USDA-style).
// Coordinates are pinned at the historically-cited center of domestication or
// first cultivation. commonsFile is a Wikimedia Commons filename; the image
// pipeline resolves it, and markers fall back to a lettered badge if it 404s.
type Row = [
  string, // id
  string, // name
  Category,
  number, // lat
  number, // lng
  string, // region
  string, // story
  number, // calories
  number, // carbs
  number, // fiber
  number, // protein
  string[], // highlights
  string, // tasteAtlas slug
  string, // commonsFile
]

function toItem(r: Row): ProduceItem {
  const [id, name, category, lat, lng, region, story, calories, carbs, fiber, protein, highlights, slug, commonsFile] = r
  return {
    id,
    name,
    category,
    origin: { lat, lng, region },
    story,
    nutrition: { per100g: { calories, carbs, fiber, protein }, highlights },
    tasteAtlasUrl: `https://www.tasteatlas.com/${slug}`,
    commonsFile,
  }
}

